sql:
SELECT COUNT(*) 
FROM feats 
WHERE is_hidden = 0 AND is_restricted = 0;

SELECT name
FROM feats
WHERE rarity_id = (SELECT rarity_id FROM rarities WHERE rarity_name = 'Common');

SELECT name
FROM feats
WHERE feat_id = 0;

SELECT rarity_id, COUNT(*) AS feat_count
     FROM feats
     GROUP BY rarity_id;

SELECT COUNT(*) AS feat_count
FROM feats
WHERE is_hidden = 0 AND source_id = (SELECT source_id FROM sources WHERE source_name = 'Core Rulebook');

external_knowledge:
- 'Uncommon feats' refers to feats with a rarity name of 'Uncommon'; 
- 'Core Rulebook' is a specific source for feats; 
- The access count is an indicator of a feat's popularity.
